mapping:
(
  $cfg := params.cfg;
  $tags := $cfg.affiliation_tags;
  $ensure_array := function($value) {
    $type($value) = "array" ? $value : ($exists($value) ? [$value] : [])
  };
  $text := function($value) {
    $type($value) = "array"
      ? $join($value.($type($) = "object" and $exists($."_text") ? $."_text" : $string($)), "")
      : ($type($value) = "object" and $exists($value."_text") ? $value."_text" : $value)
  };
  $contains_tag := function($value) {
    $count($filter($tags, function($tag) {
      $contains($lowercase($string($value)), $lowercase($string($tag)))
    })) > 0
  };
  $affiliation_infos := function($author) {
    $ensure_array($author.AffiliationInfo)
  };
  $matching_affiliation := function($author) {
    $affiliation_infos($author)[$contains_tag($text(Affiliation))][0]
  };
  $is_inst_author := function($author) {
    $exists($matching_affiliation($author))
  };
  $authors := $ensure_array($.Article.AuthorList.Author);
  $article_dates := $ensure_array($.Article.ArticleDate);
  $pad2 := function($value) {
    $pad($string($value), -2, "0")
  };
  $month_to_number := function($month) {(
    $month_text := $lowercase($string($month));
    $is_numeric := $boolean($match($month_text, /^\d+$/));
    $is_numeric ? $number($month_text) : (
      $contains($month_text, "jan") ? 1 :
      $contains($month_text, "feb") ? 2 :
      $contains($month_text, "mar") ? 3 :
      $contains($month_text, "apr") ? 4 :
      $contains($month_text, "may") ? 5 :
      $contains($month_text, "jun") ? 6 :
      $contains($month_text, "jul") ? 7 :
      $contains($month_text, "aug") ? 8 :
      $contains($month_text, "sep") ? 9 :
      $contains($month_text, "oct") ? 10 :
      $contains($month_text, "nov") ? 11 :
      $contains($month_text, "dec") ? 12 : 1
  )
  )};
  $build_date := function($year, $month, $day) {
    $year ? ($string($year) & "-" & $pad2($month ? $month : 1) & "-" & $pad2($day ? $day : 1)) : undefined
  };
  $article_date := (
    $elec := $article_dates[$contains($string(_attributes.DateType), "elec")][0];
    $picked := $elec ? $elec : $article_dates[0];
    $picked ? $build_date($text($picked.Year), $month_to_number($text($picked.Month)), $text($picked.Day)) : undefined
  );
  $journal_date := (
    $pub := $.Article.Journal.JournalIssue.PubDate;
    $pub ? $build_date($text($pub.Year), $month_to_number($text($pub.Month)), $text($pub.Day)) : undefined
  );
  $doi_values := $ensure_array($.Article.ELocationID)[_attributes.EIdType = "doi"];
  {
    "title": $text($.Article.ArticleTitle),
    "doi": $text($doi_values[0]),
    "authors_inst": $authors[$is_inst_author($)].{
      "first_name": $text(ForeName),
      "last_name": $text(LastName),
      "affiliation": $text($matching_affiliation($).Affiliation)
    }[],
    "authors": $join($authors.(
      $last := $text(LastName);
      $first := $text(ForeName);
      $last ? ($first ? $last & ", " & $first : $last) : undefined
    )[$exists($)], "; "),
    "greater_entity": {
      "label": $text($.Article.Journal.Title),
      "identifiers": $ensure_array($.Article.Journal.ISSN).{
        "type": "issn",
        "value": $text($)
      }
    },
    "pub_date": $article_date ? $article_date : $journal_date,
    "language": $text($.Article.Language),
    "pub_type": $join($ensure_array($.Article.PublicationTypeList.PublicationType).($text($))[$exists($)], ";"),
    "status": 1,
    "abstract": (
      $abstract_text := $.Article.Abstract.AbstractText."_text";
      $type($abstract_text) = "array" ? $join($abstract_text, ";") : $abstract_text
    )
  }
)
